module top_module(clk,reset,key,IRQ,Key_RD);input clk;
    input reset;

    input [7:0] key;


    output reg IRQ;
    output [31:0] Key_RD;


    reg [7:0] stored_key;

    assign Key_RD={24'b0,stored_key};

    always @(posedge clk)
        begin
            if(reset)
                begin
                    stored_key<=0;
                    IRQ<=0;
                end 
            else if(stored_key!=~key)
                begin
                    stored_key<=~key;
                    IRQ<=1;
                end
            else
                begin
                    stored_key<=stored_key;
                    IRQ<=0;
                end
        end

endmodule
